INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-f0899a01-moex-00177', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '甲意圖殺乙，於是從家中拿菜刀後，打算搭乘捷運前往乙宅外埋伏，等乙出門時將其殺害。不料收到 情報的乙早有準備，在甲搭乘捷運前往乙宅途中即報警處理。甲在出站時即被警察逮捕，菜刀亦被沒 收。甲成立何罪？', '["殺人罪的既遂犯", "殺人罪的不能未遂", "殺人罪的中止未遂", "殺人罪的預備犯"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "82bf4eaffd97", "answer_pdf_sha1": "928b35146456", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0811", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00178', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '消防員甲於乙之住宅發生火災之際，未徵得隔壁住戶丙之意願，將丙之住宅大門打破，以便進入丙住 宅頂樓救火，下列敘述何者正確？', '["火災係人為災害，不屬於刑法第24條規定之緊急危難", "甲屬於公務上或業務上有特別義務之人，其打破丙宅大門之行為，不適用刑法第24條第1項緊急避 難之規定", "甲打破丙宅大門之行為，如其係為避免他人財產遭受緊急危難時，即無適用刑法第24條緊急避難規 定之餘地", "甲打破丙宅大門之行為，必須是出於不得已之行為，始有適用刑法第24條緊急避難規定之餘地"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "82bf4eaffd97", "answer_pdf_sha1": "928b35146456", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0811", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00179', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '關於幫助犯之敘述，下列何者錯誤？', '["幫助犯之成立前提須存在一故意違法之正犯行為", "幫助行為包括物理上的助力與心理上的支持", "幫助行為僅得以積極行為為之", "幫助犯不須與正犯在心理上有所接觸"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "82bf4eaffd97", "answer_pdf_sha1": "928b35146456", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0811", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00180', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '甲教唆乙行竊，乙赴現場行竊過程中，因被發覺轉而為強盜行為，下列敘述何者正確？', '["甲應論以強盜罪之教唆犯，乙應論以竊盜罪之正犯", "甲、乙應論以強盜罪之共同正犯", "甲、乙應論以竊盜罪之共同正犯", "甲應論以竊盜罪之教唆犯，乙應論以強盜罪之正犯"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "82bf4eaffd97", "answer_pdf_sha1": "928b35146456", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0811", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00181', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '關於共同正犯的概念，下列敘述何者錯誤？', '["賭博罪應有二人以上行為人為之，屬於對向犯", "傷害罪得由單一行為人為之，亦得二人以上共同為之，屬於對合犯", "參與犯罪結社罪應有二人以上共同參與犯罪，屬於必要共同正犯", "殺人罪得由單一行為人為之，亦得二人以上共同為之，屬於任意共同正犯"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "82bf4eaffd97", "answer_pdf_sha1": "928b35146456", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0811", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00182', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '有關共同正犯主觀要件之敘述，下列何者錯誤？', '["共同正犯要求數行為人之間的犯意聯絡，並不以明示者為限，即令默示之合致，亦無不可", "依實務見解，過失犯因欠缺犯意聯絡之可能，無從成立共同正犯", "教唆犯之教唆意思本質上亦屬犯意之聯絡，故教唆犯與共同正犯之區別僅在於客觀行為分擔之不同", "司法院釋字109號解釋所指的同謀共同正犯，係指共同正犯中僅有事前同謀的犯意聯絡，客觀上並 無行為分擔之行為者而言"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "82bf4eaffd97", "answer_pdf_sha1": "928b35146456", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0811", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00183', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '依實務見解，關於共同正犯之敘述，下列何者正確？', '["共同正犯中有一人因己意而中止者，全部人均成立中止犯", "共同正犯中有一人既遂者，其他人仍為未遂", "共同正犯中有一人脫離者，全部人均為脫離", "共同正犯中有一人著手實行者，全部人均為著手實行"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "82bf4eaffd97", "answer_pdf_sha1": "928b35146456", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0811", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00184', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '甲警員因收受乙之性招待，而對其管區內乙經營之賭博場所，不予取締。下列敘述何者正確？', '["甲成立刑法第164條第1項藏匿人犯罪", "甲成立刑法第122條之收受賄賂罪", "甲成立刑法第270條之公務員包庇賭博罪", "甲成立刑法第165條之湮滅刑事證據罪之不作為犯"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "82bf4eaffd97", "answer_pdf_sha1": "928b35146456", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0811", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00185', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '關於易刑處分，下列敘述何者不會發生？', '["罰金易以訓誡", "罰金易以拘役", "3月有期徒刑易服社會勞動", "拘役易服社會勞動"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "82bf4eaffd97", "answer_pdf_sha1": "928b35146456", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0811", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00186', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '下列敘述何者非刑法第55條之想像競合的情形？', '["殺手甲舉槍射A，子彈穿透A，同時射中遠方的B，使A、B當場中彈死亡", "殺手甲投擲一顆手榴彈，使A、B、C當場均因手榴彈爆炸而死亡", "甲對A潑硫酸，使A臉部受傷且使A所騎乘之機車座墊毀損", "殺手甲受委託殺害A、B，先後於某年2月時殺害A，同年6月時再殺害B"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "82bf4eaffd97", "answer_pdf_sha1": "928b35146456", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0811", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL)
